import java.util.Date;

public class EmissionsTracker {
    private double currentEmissions;
    private double reductionGoal;

    public EmissionsTracker(double initialEmissions, double reductionGoal) {
        this.currentEmissions = initialEmissions;
        this.reductionGoal = reductionGoal;
    }

    public void updateEmissions(double newEmissions) {
        currentEmissions = newEmissions;
    }

    public double calculateProgress() {
        return ((currentEmissions - reductionGoal) / currentEmissions) * 100;
    }

    public void reportProgress() {
        double progress = calculateProgress();
        System.out.println("Current emissions: " + currentEmissions);
        System.out.println("Reduction goal: " + reductionGoal);
        System.out.println("Progress towards goal: " + progress + "%");
    }

